CREATE TABLE IF NOT EXISTS "account_group_rate_rules" ("id" INTEGER GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY, "account_id" INTEGER NOT NULL, "group_key" TEXT NOT NULL, "ratio_override" DOUBLE PRECISION NOT NULL, "created_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), "updated_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), FOREIGN KEY ("account_id") REFERENCES "accounts"("id") ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS "official_model_prices" ("id" INTEGER GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY, "provider_id" TEXT NOT NULL, "model_id" TEXT NOT NULL, "display_name" TEXT NOT NULL, "input_per_million_usd" DOUBLE PRECISION, "output_per_million_usd" DOUBLE PRECISION, "cache_read_per_million_usd" DOUBLE PRECISION, "cache_write_per_million_usd" DOUBLE PRECISION, "reasoning_per_million_usd" DOUBLE PRECISION, "input_audio_per_million_usd" DOUBLE PRECISION, "output_audio_per_million_usd" DOUBLE PRECISION, "tiers_json" JSONB, "source_updated_at" TEXT, "fetched_at" TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS "pricing_refresh_states" ("id" INTEGER GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY, "scope_type" TEXT NOT NULL, "scope_id" INTEGER NOT NULL DEFAULT 0, "last_success_at" TEXT, "last_failure_at" TEXT, "last_failure_kind" TEXT, "failure_active" BOOLEAN NOT NULL DEFAULT false, "created_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), "updated_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'));
CREATE TABLE IF NOT EXISTS "site_model_price_rules" ("id" INTEGER GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY, "site_id" INTEGER NOT NULL, "upstream_model_id" TEXT NOT NULL, "mapped_provider_id" TEXT, "mapped_model_id" TEXT, "mapping_mode" TEXT NOT NULL, "input_override_usd" DOUBLE PRECISION, "output_override_usd" DOUBLE PRECISION, "cache_read_override_usd" DOUBLE PRECISION, "cache_write_override_usd" DOUBLE PRECISION, "reasoning_override_usd" DOUBLE PRECISION, "input_audio_override_usd" DOUBLE PRECISION, "output_audio_override_usd" DOUBLE PRECISION, "per_call_override_usd" DOUBLE PRECISION, "created_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), "updated_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), FOREIGN KEY ("site_id") REFERENCES "sites"("id") ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS "site_model_prices" ("id" INTEGER GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY, "site_id" INTEGER NOT NULL, "upstream_model_id" TEXT NOT NULL, "input_per_million_usd" DOUBLE PRECISION, "output_per_million_usd" DOUBLE PRECISION, "cache_read_per_million_usd" DOUBLE PRECISION, "cache_write_per_million_usd" DOUBLE PRECISION, "reasoning_per_million_usd" DOUBLE PRECISION, "input_audio_per_million_usd" DOUBLE PRECISION, "output_audio_per_million_usd" DOUBLE PRECISION, "per_call_usd" DOUBLE PRECISION, "pricing_semantics" TEXT NOT NULL, "raw_metadata_json" JSONB, "fetched_at" TEXT NOT NULL, FOREIGN KEY ("site_id") REFERENCES "sites"("id") ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS "site_pricing_profiles" ("site_id" INTEGER NOT NULL PRIMARY KEY, "paid_cny" DOUBLE PRECISION NOT NULL DEFAULT 1, "credited_usd" DOUBLE PRECISION NOT NULL DEFAULT 1, "created_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), "updated_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), FOREIGN KEY ("site_id") REFERENCES "sites"("id") ON DELETE CASCADE);
